patch:
diff --git a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
index e44777c5c485..6785b14d7b2b 100644
--- a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
+++ b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
@@ -779,6 +779,27 @@ InstructionCost SystemZTTIImpl::getCastInstrCost(unsigned Opcode, Type *Dst,
   unsigned DstScalarBits = Dst->getScalarSizeInBits();
   unsigned SrcScalarBits = Src->getScalarSizeInBits();

+  // Handle scalar <-> vector non-bitcast casts.
+  if (Src->isVectorTy() != Dst->isVectorTy() && Opcode != Instruction::BitCast) {
+    // Scalarize the cast.
+    if (Src->isVectorTy()) {
+      // Vector to scalar.
+      auto *SrcVecTy = cast<FixedVectorType>(Src);
+      unsigned VF = SrcVecTy->getNumElements();
+      InstructionCost ScalarCost = getCastInstrCost(Opcode, Dst, Src->getScalarType(), CCH, CostKind, I);
+      InstructionCost TotCost = VF * ScalarCost;
+      TotCost += getScalarizationOverhead(SrcVecTy, /*Insert*/ false, /*Extract*/ true, CostKind);
+      return TotCost;
+    } else {
+      // Scalar to vector.
+      auto *DstVecTy = cast<FixedVectorType>(Dst);
+      unsigned VF = DstVecTy->getNumElements();
+      InstructionCost ScalarCost = getCastInstrCost(Opcode, Dst->getScalarType(), Src, CCH, CostKind, I);
+      InstructionCost TotCost = VF * ScalarCost;
+      TotCost += getScalarizationOverhead(DstVecTy, /*Insert*/ true, /*Extract*/ false, CostKind);
+      return TotCost;
+    }
+  }
   if (!Src->isVectorTy()) {
     assert (!Dst->isVectorTy());

